// Validacion de origen — para activar, poner el secreto en secretEsperado
const secretEsperado = '';
const secretRecibido = $input.first().json.headers?.['x-n8n-secret'] || '';

if (secretEsperado && secretRecibido !== secretEsperado) {
  throw new Error('401 Unauthorized: X-N8N-Secret invalido o ausente');
}

return $input.all();

// Valida que se recibio un archivo y extrae metadata del formulario
const item = $input.first();
const binaryData = item.binary;

// Verificar que existe el archivo
// Nota: n8n crea el key como binaryPropertyName + indice (data0+0 = data00)
if (!binaryData || (!binaryData.data0 && !binaryData.data00 && !binaryData.documento)) {
  throw new Error('400 Bad Request: No se recibio ningun archivo. Por favor adjunta un PDF o documento de texto.');
}

const archivoBin = binaryData.data0 || binaryData.data00 || binaryData.documento;
const fileName = archivoBin.fileName || 'documento.pdf';
const fileMime = archivoBin.mimeType || 'application/pdf';
const fileSizeBytes = archivoBin.fileSize || 0;
const fileSizeMB = fileSizeBytes / (1024 * 1024);

// Limitar a 50MB
if (fileSizeMB > 50) {
  throw new Error(`400 Bad Request: El archivo '${fileName}' supera el limite de 50MB (${fileSizeMB.toFixed(1)}MB). Comprime o divide el documento.`);
}

// Tipos de archivo aceptados
const mimesAceptados = ['application/pdf', 'text/plain', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
if (!mimesAceptados.some(m => fileMime.includes(m.split('/')[1])) && !fileName.match(/\.(pdf|txt|docx)$/i)) {
  throw new Error(`415 Unsupported Media Type: Solo se aceptan archivos PDF, TXT o DOCX. Recibido: ${fileMime}`);
}

// Extraer campos del formulario — n8n ubica texto en json directamente en multipart
const sector = ((item.json.sector || item.json.body?.sector || 'GENERAL') + '').toUpperCase().trim();
const empresa = (item.json.empresa || item.json.body?.empresa || 'Empresa').toString().trim();
const sessionId = item.json.session_id || item.json.body?.session_id || `drc-${Date.now()}`;

const sectoresValidos = ['AGRO', 'NAVAL', 'AEREO', 'ENERGIA', 'GENERAL'];
const sectorFinal = sectoresValidos.includes(sector) ? sector : 'GENERAL';

// Sanitizar empresa (solo alfanumericos, espacios y guiones)
const empresaSanitizada = empresa.replace(/[^\w\sáéíóúÁÉÍÓÚñÑ.,\-]/g, '').substring(0, 100);

// Preservar el binario en data0 para el siguiente nodo
const keyOriginal = binaryData.data0 ? 'data0' : 'documento';

return [{
  json: {
    sector: sectorFinal,
    empresa: empresaSanitizada,
    session_id: sessionId,
    nombre_archivo: fileName,
    tipo_archivo: fileMime,
    tamano_mb: parseFloat(fileSizeMB.toFixed(2))
  },
  binary: { data0: archivoBin }
}];

// Recuperar texto extraido y metadata del nodo anterior
const textoExtraido = ($input.first().json.text || $input.first().json.data || '').toString();

// Referencia a metadata guardada en Validar Archivo
const sector = $('Validar Archivo').item.json.sector;
const empresa = $('Validar Archivo').item.json.empresa;
const sessionId = $('Validar Archivo').item.json.session_id;
const nombreArchivo = $('Validar Archivo').item.json.nombre_archivo;
const tamanioMB = $('Validar Archivo').item.json.tamano_mb;

// Verificar que el PDF tiene texto extraible
if (!textoExtraido || textoExtraido.trim().length < 50) {
  throw new Error('422 Unprocessable Entity: El documento no contiene texto extraible. Posiblemente es un PDF escaneado (imagen). Utiliza un PDF con texto seleccionable o convierte con OCR primero.');
}

// Mapa de variables criticas por sector
const variablesPorSector = {
  AGRO: [
    '- Precipitacion acumulada y proyectada (mm)',
    '- Temperaturas maximas, minimas y medias del suelo y del aire (°C)',
    '- Humedad relativa y deficit de presion de vapor (%)',
    '- Alertas de heladas, granizo, sequia o inundacion',
    '- Indices agroclimaticos: ETo, GDD, estres hidrico',
    '- Ventanas optimas de siembra, cosecha o aplicacion de agroquimicos',
    '- Fases lunares y su impacto en ciclos vegetativos'
  ].join('\n'),
  NAVAL: [
    '- Velocidad y direccion del viento en zona de operacion (nudos/grados)',
    '- Altura significativa de olas y periodo de pico (metros/seg)',
    '- Visibilidad maritima y presencia de neblina (km)',
    '- Estado de mareas, corrientes y surgencias costeras',
    '- Ventanas operativas seguras (fechas y horas)',
    '- Alertas de temporal, ciclon, tsunami o condiciones adversas',
    '- Puerto de refugio recomendado y restricciones de zarpe'
  ].join('\n'),
  AEREO: [
    '- Condiciones METAR/TAF vigentes: visibilidad, techo de nubes, QNH',
    '- Turbulencias reportadas o pronosticadas (nivel CAT y severidad)',
    '- Alertas SIGMET/AIRMET activas en la region',
    '- Vientos en altura, tropopausa y jet stream relevantes',
    '- Riesgos de engelamiento (icing) en ruta o destino',
    '- Tormentas eléctricas y cizalladura del viento (wind shear)',
    '- Ventanas optimas de operacion VFR/IFR y alternativas de desvio'
  ].join('\n'),
  ENERGIA: [
    '- Generacion total y desglose por fuente (GWh/MWh: solar, eolica, termica)',
    '- Demanda pico, valle y promedio del periodo analizado',
    '- Precio spot y precio del mercado energetico mayorista ($/MWh)',
    '- Porcentaje de penetracion de energias renovables en la matriz',
    '- Temperatura ambiental promedio y correlacion con demanda',
    '- Proyeccion de generacion/demanda para el siguiente periodo',
    '- Restricciones de red, cortes programados o situaciones de emergencia'
  ].join('\n'),
  GENERAL: [
    '- Variables cuantitativas mas importantes del documento',
    '- Indicadores de riesgo, alertas criticas o situaciones de emergencia',
    '- Tendencias principales y anomalias detectadas',
    '- Recomendaciones operativas inmediatas y de corto plazo',
    '- Proyecciones, estimaciones o datos prospectivos clave',
    '- Cualquier valor fuera de rango normal que requiera accion'
  ].join('\n')
};

const variables = variablesPorSector[sector] || variablesPorSector.GENERAL;

// Limitar texto a 80.000 chars para no exceder tokens de Gemini Flash
const LIMITE_CHARS = 80000;
const textoCortado = textoExtraido.length > LIMITE_CHARS;
const textoFinal = textoCortado
  ? textoExtraido.substring(0, LIMITE_CHARS) + '\n\n[--- DOCUMENTO TRUNCADO POR LONGITUD: se procesaron los primeros 80.000 caracteres ---]'
  : textoExtraido;

// Construir el JSON de ejemplo de respuesta usando JSON.stringify para evitar problemas de escape
const esquemaRespuesta = JSON.stringify({
  empresa: empresa,
  sector: sector,
  documento_procesado: '<tipo o nombre del documento analizado>',
  periodo_cubierto: '<periodo temporal del reporte, ej: Febrero 2026, o null>',
  resumen_ejecutivo: [
    '<viñeta 1 con emoji de urgencia>',
    '<viñeta 2 con emoji de urgencia>',
    '<viñeta 3 con emoji de urgencia>',
    '<viñeta 4 con emoji de urgencia>',
    '<viñeta 5 con emoji de urgencia>'
  ],
  alerta_critica: '<descripcion de la alerta mas urgente del documento, o null si no hay alertas>',
  proxima_accion: '<la accion operativa inmediata mas importante que debe tomar la empresa>',
  confianza_extraccion: 'alta|media|baja'
}, null, 2);

const prompt = `Eres un analista experto en meteorologia operativa y gestion de riesgos para el sector ${sector}, trabajando para la empresa "${empresa}".

Tu tarea: leer el siguiente documento tecnico completo y extraer UNICAMENTE las variables criticas de mayor impacto operativo para las actividades diarias de la empresa.

== VARIABLES PRIORITARIAS A IDENTIFICAR ==
${variables}

== DOCUMENTO A ANALIZAR ==
---
${textoFinal}
---
== FIN DEL DOCUMENTO ==

== INSTRUCCIONES ESTRICTAS ==
1. Genera EXACTAMENTE 5 vinetas ejecutivas en "resumen_ejecutivo"
2. Cada vineta debe ser: concisa (maximo 2 oraciones), 100% accionable, con valores numericos concretos cuando esten disponibles
3. Usa SIEMPRE estos prefijos de urgencia al inicio de cada vineta:
   - 🔴 CRITICO: requiere accion inmediata (alertas, valores extremos)
   - 🟡 ATENCION: requiere monitoreo proximo (valores en limite, tendencias)
   - 🟢 NORMAL: condicion dentro de parametros (informacion favorable)
   - 🔵 INFO: dato relevante sin urgencia operativa
4. Prioriza alertas y valores que requieran accion en las proximas 24-72 horas
5. Si no hay suficientes datos para una vineta, escribe exactamente: "🔵 INFO: Sin datos suficientes en el documento para esta categoria"
6. El campo "alerta_critica" debe ser null (sin comillas) si no hay alertas 🔴
7. Sé especifico: menciona fechas, horas, coordenadas o regiones geograficas si el documento las incluye

RESPONDE SOLAMENTE CON EL SIGUIENTE JSON (absolutamente sin markdown, sin bloques de codigo, sin texto adicional antes o despues):
${esquemaRespuesta}`;

// Construir el cuerpo de la request para Gemini API
const requestBody = {
  contents: [{
    role: 'user',
    parts: [{ text: prompt }]
  }],
  generationConfig: {
    temperature: 0.15,
    maxOutputTokens: 2048,
    topP: 0.8,
    topK: 40
  },
  safetySettings: [
    { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
  ]
};

return [{
  json: {
    requestBody: requestBody,
    // Metadata para nodos posteriores
    sector: sector,
    empresa: empresa,
    session_id: sessionId,
    nombre_archivo: nombreArchivo,
    texto_chars: textoFinal.length,
    texto_truncado: textoCortado,
    tamano_mb: tamanioMB
  }
}];

const response = $input.first().json;
const promptData = $('Preparar Prompt Sectorial').item.json;

let analisis = {};
let parseExitoso = false;
let rawText = '';

try {
  // Extraer texto de la respuesta de Gemini API
  rawText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';

  if (!rawText) {
    const finishReason = response.candidates?.[0]?.finishReason || 'UNKNOWN';
    throw new Error(`Gemini no devolvio texto. Razon de finalizacion: ${finishReason}`);
  }

  // Limpiar posibles bloques markdown que Gemini pueda incluir a pesar de las instrucciones
  const cleanText = rawText
    .replace(/^```json[\s\r\n]*/i, '')
    .replace(/^```[\s\r\n]*/i, '')
    .replace(/[\s\r\n]*```$/i, '')
    .trim();

  analisis = JSON.parse(cleanText);
  parseExitoso = true;

} catch(e) {
  // Fallback robusto: construir respuesta degradada pero util
  analisis = {
    empresa: promptData.empresa,
    sector: promptData.sector,
    documento_procesado: promptData.nombre_archivo,
    periodo_cubierto: null,
    resumen_ejecutivo: [
      `🔵 INFO: El documento '${promptData.nombre_archivo}' fue recibido y se extrajeron ${promptData.texto_chars.toLocaleString()} caracteres`,
      '🟡 ATENCION: No se pudo estructurar la respuesta de la IA en formato JSON',
      `🔵 INFO: Texto truncado: ${promptData.texto_truncado ? 'SI (documento muy extenso)' : 'NO'}`,
      '🔵 INFO: Reintente con el mismo archivo; puede ser un fallo temporal de la API',
      '🔵 INFO: Si el problema persiste, verifique que el PDF contiene texto seleccionable'
    ],
    alerta_critica: null,
    proxima_accion: 'Reintentar el analisis o revisar la calidad del PDF',
    confianza_extraccion: 'baja'
  };
}

return [{
  json: {
    success: parseExitoso,
    analisis: analisis,
    metadata: {
      session_id: promptData.session_id,
      nombre_archivo: promptData.nombre_archivo,
      sector: promptData.sector,
      empresa: promptData.empresa,
      tamano_mb: promptData.tamano_mb,
      caracteres_procesados: promptData.texto_chars,
      texto_truncado: promptData.texto_truncado,
      modelo_ia: 'gemini-2.0-flash',
      parse_exitoso: parseExitoso,
      timestamp: new Date().toISOString()
    }
  }
}];
